module RAM
#(
    parameter WIDTH = 6,
    parameter DEPTH = 8
)
(
    input clk,
    input rst_n,
    input write_en,
    input [$clog2(DEPTH)-1:0] write_addr,
    input [WIDTH-1:0] write_data,
    input read_en,
    input [$clog2(DEPTH)-1:0] read_addr,
    output reg [WIDTH-1:0] read_data
);
parameter WIDTH = 6;
parameter DEPTH = 8;
reg [3:0] i;
task initialize_RAM;
    for (i = 0; i < DEPTH; i = i + 1) begin RAM[i] = 0; end
always @(*) begin
    if (!rst_n) begin
        read_data = 6'b000000;
    end else begin
        if (read_en) begin
            read_data = RAM[read_addr];
        end else begin
            RAM[write_addr] = write_data;
        end
    end
end
endmodule
